// Solo extrae datos del admin. La construccion del prompt completo (con memoria) se hace en 'Armar prompt completo'.
const src = $input.first().json;
const b = (src.body && typeof src.body === 'object') ? src.body : src;
const admin_whatsapp = b.admin_whatsapp || b.from || '';
const admin_body = b.admin_body || b.text || b.message || '';
// respond_to = a donde el bot responde. En 1-a-1 es el mismo admin. En grupo, es el JID del grupo.
const respond_to = b.respond_to || admin_whatsapp;
if (!admin_whatsapp || !admin_body) {
  return [{ json: { _error: 'inputs_incompletos', admin_whatsapp, admin_body } }];
}
return [{ json: { admin_whatsapp, admin_body, respond_to } }];

const resp = $input.first().json;
let content = '';
try { content = resp.choices[0].message.content; } catch (e) {}
let parsed = {};
try { parsed = JSON.parse(content); } catch (e) { parsed = { accion: 'sin_accion', cliente: '', tipo: '', cantidad: 0 }; }
const prep = $('Preparar prompt').first().json;
const memCtx = $('Cargar memoria admin').first().json;
const hist = memCtx.historial || [];
const CAMPOS_OK = ['nombre','instagram','email','paquete','tipificacion','opt_out_marketing'];
const telDigits = String(parsed.telefono || '').replace(/\D/g, '');
const campo = String(parsed.campo || '').toLowerCase();
const campoValido = CAMPOS_OK.includes(campo);
let accion = parsed.accion || 'sin_accion';
let confirmado = !!parsed.confirmado;
if (accion === 'edit_lead' && !campoValido) accion = 'sin_accion';
if (accion === 'edit_lead' && !telDigits && !(parsed.cliente || '').trim()) accion = 'sin_accion';
if (accion === 'delete_lead' && !telDigits && !(parsed.cliente || '').trim()) accion = 'delete_lead_sin_tel';
// Recarga sin cantidad valida (0 o negativa) -> pedir aclaracion. Cualquier entero positivo es aceptado.
const cantidadValida = Number.isInteger(parsed.cantidad) && parsed.cantidad > 0;
if (accion === 'recarga' && !cantidadValida) accion = 'recarga_pendiente';
if (accion === 'recarga_y_asistencia' && !cantidadValida) accion = 'recarga_y_asistencia_pendiente';
if (accion === 'ajustar_saldo') {
  const c = Number(parsed.cantidad);
  if (!Number.isInteger(c) || c < 0 || c > 999) accion = 'sin_accion';
}

// Parser de lista para bulk_load (regex, no LLM). Soporta: '573XXX Nombre', '+57 300 123 4567 Nombre @ig email@x.com'.
function parseList(text) {
  if (!text) return [];
  const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
  const out = [];
  for (const line of lines) {
    // Saltar lineas de comando o header (sin telefono): "carga estos clientes:", "nuevos leads:", etc.
    if (!/\d/.test(line) && /(carga|agrega|a\u00f1ade|anade|incluye|nuevos|estos|esta|esos|esas|clientes|leads?|persona|lista)/i.test(line)) continue;
    const telMatch = line.match(/\+?\d[\d\s\-]{7,18}\d/);
    if (!telMatch) continue;
    let tel = telMatch[0].replace(/\D/g, '');
    // Normalizar Colombia: 10 digitos que arrancan en 3 -> 57+
    if (tel.length === 10 && tel[0] === '3') tel = '57' + tel;
    if (tel.length < 10) continue;
    const igMatch = line.match(/@([\w._]+)/);
    const ig = igMatch ? igMatch[1] : '';
    const emailMatch = line.match(/[\w.+-]+@[\w.-]+\.\w{2,}/);
    const email = emailMatch ? emailMatch[0] : '';
    let nombre = line
      .replace(telMatch[0], '')
      .replace(/@[\w._]+/g, '')
      .replace(emailMatch ? emailMatch[0] : '', '')
      .replace(/[\s,;]+/g, ' ')
      .trim();
    // Strip de prefijos de comando que el admin haya escrito en la misma linea ("carga este cliente NombreReal")
    nombre = nombre
      .replace(/^(carga|agrega|a\u00f1ade|anade|incluye|incluye[au]?|registra|crea|cr[eé]al[oa]?)\s+(este|esos|estos|esa|esas|los|las|al|a)?\s*(cliente|clientes|lead|leads|persona|personas|nuevo|nueva|miembro)?\s+/i, '')
      .replace(/^(este|esos|estos|esa|esas)\s+(cliente|clientes|lead|leads|persona|personas)\s+/i, '')
      .replace(/^(a|al|para|de)\s+/i, '')
      .trim();
    // Limpiar comentarios/data extra que el admin haya metido junto al nombre
    nombre = nombre
      .replace(/\s+le\s+(quedan?|falta[n]?|tiene[n]?)\s+\d+\s+clase[s]?.*$/i, '')
      .replace(/\s+(tiene|trae)\s+\d+\s+clase[s]?.*$/i, '')
      .replace(/\s+(asisti[oó]|vino|pag[oó]|pagaron|recarg[oó])\b.*$/i, '')
      .replace(/\s+saldo\s+\d+.*$/i, '')
      .replace(/[\s,;.:]+$/g, '')
      .trim();
    if (!nombre || nombre.length < 2) continue;
    out.push({ tel, nombre, ig, email });
  }
  return out;
}

// Parser de nombres para bulk_asistencia: una linea o coma por nombre, sin telefonos.
// Rechaza lineas que parecen prosa (verbos conjugados, conectores comunes) — solo acepta lineas tipo nombre.
function looksLikeName(s) {
  const words = s.split(/\s+/).filter(Boolean);
  if (words.length === 0 || words.length > 5) return false;
  // Verbos conjugados o particulas que indican prosa
  if (/\b(es|son|fue|fueron|tiene|tienen|hubo|hay|pag[oóa]|pagaron|toma|tomaron|asisti[oó]|asistieron|consumi[oó]|consumieron|quier[oea]|necesit[oa]|paso|pasaron|incluy[ea]|inclu[íi]?yel|agreg[ae]|registr[ae]|registra|registro|registrar|cambi[oa]|cambia|corrige|corrig[ió]|ajust[ae]|ajusta|cancela|cancel[oó]|gracias|hola|listo|sirve|sirven|fueron)\b/i.test(s)) return false;
  // Conectores y frases de prosa
  if (/\b(por\s+favor|cu[áa]ntas?|cu[áa]nt[oa]s|qu[eé]\s+(personas|clientes)|de\s+las\s+cuales|de\s+los\s+cuales|el\s+n[uú]mero|tel[eé]fono|le\s+(quedan?|dist[eé])|ya\s+(consum|gast)|para\s+que)\b/i.test(s)) return false;
  return true;
}
function parseNombres(text) {
  if (!text) return [];
  // Quita encabezados tipo 'asistieron:', 'vinieron:' al inicio
  const cleaned = text.replace(/^(BEJA\s+)?(asistieron|vinieron|estuvieron|hoy|presentes|registro)\s*:?\s*/i, '').trim();
  // Split por linea; comas se procesan dentro de cada linea
  const lines = cleaned.split(/[\n;]+/).map(l => l.trim()).filter(Boolean);
  const out = [];
  for (const line of lines) {
    // Saltar lineas que terminan en ':' (son encabezados/preambulos tipo "Ayer asistieron a clase:")
    if (line.endsWith(':')) continue;
    if (/^(BEJA|registra|consulta|recarga|asistencia[s]?|asistieron|vinieron)$/i.test(line)) continue;
    if (/^\d+$/.test(line.replace(/\s/g, ''))) continue;
    if (line.length < 2) continue;
    // Dentro de la linea, separar por comas (caso 'Maria, Juan, Pedro')
    const parts = line.split(',').map(p => p.trim()).filter(Boolean);
    for (const p of parts) {
      if (p.length < 2) continue;
      if (/^\d+$/.test(p.replace(/\s/g, ''))) continue;
      // Filtro final: la parte debe parecer un nombre, no una oracion
      if (!looksLikeName(p)) continue;
      out.push(p);
    }
  }
  return out;
}

let nombres_array = [];
let asistencias_array = [];
if (accion === 'bulk_asistencia') {
  if (!confirmado) {
    nombres_array = parseNombres(prep.admin_body).slice(0, 30);
    if (nombres_array.length === 0) accion = 'sin_accion';
  } else {
    // Reconstruir asistencias_array desde el ultimo mensaje 'out' del bot que liste asistencias.
    // Acepta 'Voy a registrar asistencia' (todos ✓) o 'Encontré problemas en la lista' (confirmacion parcial, solo los ✓).
    // Soporta nombres con parentesis internos como 'Andrea Mendez (test)' anclando al ultimo (telefono) al final de linea.
    const botMsgs = hist.filter(m => m.dir === 'out');
    for (let i = botMsgs.length - 1; i >= 0; i--) {
      const t = botMsgs[i].texto || '';
      if ((/Voy a registrar asistencia/i.test(t) || /Encontré problemas en la lista/i.test(t)) && /\((\d{10,})\)/.test(t)) {
        const lines = t.split('\n');
        for (const line of lines) {
          const phoneMatch = line.match(/\((\d{10,})\)\s*$/);
          if (!phoneMatch) continue;
          const telefono = phoneMatch[1];
          let nombre = line.slice(0, phoneMatch.index).trim();
          nombre = nombre.replace(/^[^A-Za-zÀ-ÿ]+/, '').trim();   // strip emojis/simbolos al inicio
          if (nombre) asistencias_array.push({ nombre, telefono });
        }
        break;
      }
    }
    if (asistencias_array.length === 0) accion = 'sin_accion';
  }
}

let leads_array = [];
// Helper: merge LLM-cleaned names into regex-extracted phones
function mergeLLMNames(regexLeads, llmProposed) {
  if (!Array.isArray(llmProposed) || llmProposed.length === 0) return regexLeads;
  const cleanByTel = {};
  for (const lp of llmProposed) {
    const tel = String(lp.telefono || '').replace(/\D/g, '');
    const nombre = String(lp.nombre || '').trim();
    if (tel.length >= 10 && nombre.length >= 2) cleanByTel[tel] = nombre;
  }
  return regexLeads.map(l => cleanByTel[l.tel] ? { ...l, nombre: cleanByTel[l.tel] } : l);
}
if (accion === 'bulk_load' || accion === 'bulk_delete') {
  let raw = '';
  if (!confirmado) {
    raw = prep.admin_body;
  } else {
    // Buscar el mensaje del admin (rol 'user') mas reciente con telefonos o palabras de bulk
    const userMsgs = hist.filter(m => m.dir === 'in');
    for (let i = userMsgs.length - 1; i >= 0; i--) {
      const t = userMsgs[i].texto || '';
      const phones = (t.match(/\+?\d[\d\s\-]{7,18}\d/g) || []).length;
      if (phones >= 1 || /carga|agrega|a\u00f1ade|leads?:|clientes:|elimina|borra|quita/i.test(t)) {
        raw = t;
        break;
      }
    }
  }
  leads_array = parseList(raw).slice(0, 50); // tope seguro de 50 por operacion
  // Mezclar nombres limpios del LLM cuando coinciden por telefono
  leads_array = mergeLLMNames(leads_array, parsed.leads_propuestos);
  if (leads_array.length === 0 && accion === 'bulk_load') {
    accion = 'bulk_load_sin_tel';
    nombres_array = parseNombres(raw).slice(0, 30);
  } else if (leads_array.length === 0 && accion === 'bulk_delete') {
    accion = 'sin_accion';
  }
}

const p = {
  accion,
  cliente: (parsed.cliente || '').trim(),
  tipo: parsed.tipo || 'presencial',
  cantidad: Number.isInteger(parsed.cantidad) ? parsed.cantidad : 0,
  telefono: telDigits,
  campo: campoValido ? campo : '',
  nuevo_valor: String(parsed.nuevo_valor || ''),
  confirmado,
  leads_array,
  nombres_array,
  asistencias_array,
  admin: prep.admin_whatsapp
};
const respuesta_libre = String(parsed.respuesta_libre || '').trim();
return [{ json: { admin_whatsapp: prep.admin_whatsapp, p1_json: JSON.stringify(p), accion, confirmado, campo: p.campo, telefono: p.telefono, nuevo_valor: p.nuevo_valor, leads_array, nombres_array, asistencias_array, bulk_count: leads_array.length, bulk_asis_count: nombres_array.length || asistencias_array.length, respuesta_libre } }];

const r = $input.first().json;
const prep = $('Preparar prompt').first().json;
const admin_whatsapp = prep.admin_whatsapp;
const respond_to = prep.respond_to || prep.admin_whatsapp;
const accion = r.accion;
const nombre = r.nombre;
const tel = r.telefono;
const saldo = r.clases_restantes;
const n = r.n_matches || 0;
let admin_text = '';
let aviso_cliente = '';
let cliente_whatsapp = '';
let resumen_renovacion = '';
let cliente_renov_tel = '';

// bulkLoadSaldoHint: detecta si el mensaje del bulk_load incluyo info de clases/saldo (que el parser ignora) y devuelve un aviso para el admin. Vacio si no hay nada.
function bulkLoadSaldoHint(body) {
  const t = String(body || '').toLowerCase();
  if (/(le\s+quedan?\s+\d|tiene\s+\d+\s+clase|ya\s+consumi[oó]|ya\s+gast[oó]|le\s+falta[n]?\s+\d|saldo\s+\d|paquete\s+(presencial|virtual|de\s+\d)|en\s+su\s+(primera|segunda|tercera|cuarta|quinta|sexta|s[eé]ptima|octava)\s+clase|asisti[oó]\s+\d+\s+vez|de\s+\d+\s+clases?\s+(pago|consumi|tomo)|paquete\s+(de\s+)?(4|8|cuatro|ocho))/i.test(t)) {
    return '\n\n📌 Detecté info sobre clases o saldos en tu mensaje, pero solo creé los leads (sin cargar saldo). Si necesitas cargar el saldo a alguno, dime: "BEJA ajusta a N las clases de Nombre" (uno por uno).';
  }
  return '';
}

// smartFallback: cuando no entiendo, doy una pista útil según lo que parece haber querido el admin.
function smartFallback(body) {
  const t = String(body || '').toLowerCase().trim();
  // Cancelacion explicita (red de seguridad si el LLM no rellena respuesta_libre)
  if (/^(no|no\s+quiero|cancela[r]?|mejor\s+no|negativo|nel|nope|mejor\s+luego|cancel[ao])[.!?\s]*$/i.test(t)) {
    return 'Listo, cancelado. Si necesitas algo más, dime.';
  }
  // Saludos
  if (/^(hola|buenas?(\s+(d[íi]as|tardes|noches))?|qu[eé]\s+tal|ey|hey|saludos|holi|holaa+)[.!?\s]*$/i.test(t)) {
    return '¡Hola! Soy el agente de Bejauha para ayudarte con asistencias, recargas, ajustes y cargue de clientes. Dime qué necesitas (ej. "Laura asistió", "Pedro pagó 8 clases"), o escribe "ayuda" para ver todo lo que puedo hacer.';
  }
  // Agradecimientos / confirmaciones cortas
  if (/^(gracias|mil\s+gracias|muchas\s+gracias|thanks?|ok|okey|okay|listo|perfecto|excelente|ch[eé]vere|genial|dale)[.!?\s]*$/i.test(t)) {
    return '¡Con gusto! 🌿 Si necesitas algo más, dime.';
  }
  // Despedidas
  if (/^(chao|ad[ií]os|hasta\s+luego|nos\s+vemos|bye|hasta\s+pronto|hasta\s+ma[ñn]ana)[.!?\s]*$/i.test(t)) {
    return '¡Hasta luego! Aquí estoy si necesitas algo.';
  }
  // Ayuda / qué hace
  if (/(qu[eé]\s+(puedes|pod[eé]s|sabes)\s+hacer|^\s*ayuda\s*$|^\s*help\s*$|c[oó]mo\s+funcionas?|qu[eé]\s+haces|men[uú]|comandos|opciones)/i.test(t)) {
    return 'Soy el agente admin de Bejauha. Te ayudo con:\n\n• *Asistencias*: "Laura asistió" o "asistieron:" + lista\n• *Recargas*: "Pedro pagó 8 clases" (cualquier cantidad)\n• *Pago + asistencia*: "Laura pagó 4 y tomó clase"\n• *Consultas*: "¿cuántas le quedan a Ana?"\n• *Ajuste manual*: "ajusta a 2 las clases de María"\n• *Pausar*: "pausa el paquete de Laura" / "despausa a Laura"\n• *Cargar clientes*: "carga estos clientes: 573XXX Nombre"\n• *Actualizar datos*: "actualiza el nombre del 573XXX a Pepito"\n\nDashboard:\nhttps://n8n.srv1398596.hstgr.cloud/webhook/bejauha-dashboard?token=bjh_NssQxwv-fbPZnSPI8fnzPmUX3Kbp1v3Ymy006w';
  }
  if (/(corrige|corregir|arregla|arreglar|ajusta|ajustar|modific|cambia\s+las\s+clases|actualiza\s+(el\s+)?saldo|ponle|d[eé]jale|ya\s+consumi[oó]|ya\s+gast[oó]|de\s+las\s+cuales)/i.test(t)) {
    return 'Si quieres ajustar el saldo, dime así:\n• "BEJA ajusta a 2 las clases de Claudia" o\n• "BEJA Claudia tiene 2 clases"\nPediré confirmación antes de aplicar.';
  }
  if (/(personas?\s+activas|qui[eé]nes?\s+tienen|qu[eé]\s+personas|lista\s+(de\s+)?(activos|clientes)|todos\s+(los\s+)?activos)/i.test(t)) {
    return 'Para ver clientes activos abre el dashboard:\nhttps://n8n.srv1398596.hstgr.cloud/webhook/bejauha-dashboard?token=bjh_NssQxwv-fbPZnSPI8fnzPmUX3Kbp1v3Ymy006w\n\nPor WhatsApp aún no tengo un listado completo, solo consultas por nombre.';
  }
  if (/(incl[uú]yel|incluye|reg[ií]strala|reg[ií]stral|agr[eé]g[au]|crea|cr[eé]ala)/i.test(t)) {
    return 'Para crear un cliente nuevo necesito el teléfono. Mándame así:\nBEJA carga estos clientes:\n573001112233 Nombre Apellido';
  }
  if (/(deshac|borra|elimin|cancela\s+la\s+asist)/i.test(t)) {
    return 'Deshacer una asistencia mal registrada todavía no lo puedo hacer. Avisa al equipo y se corrige en la base.';
  }
  return 'No entendí la acción. Puedes decir cosas como "Laura asistió", "Pedro pagó 8 clases", "¿cuántas le quedan a Ana?" o "actualiza el nombre del 573XXX a Pepito".';
}

if (accion === 'bulk_asistencia') {
  const confirmado = !!r.confirmado;
  if (!confirmado) {
    const preview = r.bulk_asis_preview || [];
    if (preview.length === 0) {
      admin_text = 'No detecté ningún nombre en la lista. Mándame los nombres uno por línea, por ej.:\nasistieron:\nMariana\nPedro\nMaria';
    } else {
      const lineas = preview.map(p => {
        if (p.n_matches === 1) {
          const m = p.matches[0];
          return '✓ ' + m.nombre + ' (' + m.telefono + ')';
        }
        if (p.n_matches === 0) return '✗ "' + p.nombre_buscado + '" — no encontré a nadie';
        const opciones = p.matches.map(x => x.nombre).join(', ');
        return '⚠️ "' + p.nombre_buscado + '" — hay varios: ' + opciones;
      });
      const allOk = preview.every(p => p.n_matches === 1);
      const modalidadLabel = (r.tipo === 'virtual') ? '*VIRTUAL*' : '*PRESENCIAL*';
      const avisoVirtual = (r.tipo === 'virtual') ? '\n\n⚠️ Atención: estás registrando asistencias VIRTUALES (lo más común es presencial). Si te equivocaste, responde "no" y reenvía sin la palabra "virtual".' : '';
      if (allOk) {
        admin_text = 'Voy a registrar asistencia ' + modalidadLabel + ' de:\n' + lineas.join('\n') + avisoVirtual + '\n\n¿Confirmas? (responde sí o no)';
      } else {
        const ambiguos = preview.filter(p => p.n_matches > 1).length;
        const noEncontrados = preview.filter(p => p.n_matches === 0).length;
        const encontrados = preview.filter(p => p.n_matches === 1).length;
        let consejo = '';
        if (ambiguos > 0 && noEncontrados > 0) {
          consejo = 'Para los ambiguos (⚠️) mándame el nombre más específico o apellido. Para los que no encontré (✗): si son clientes nuevos primero agrégalos con "BEJA carga estos clientes: 573XXX Nombre" y después reenvíame la lista de asistencia.';
        } else if (ambiguos > 0) {
          consejo = 'Para los ambiguos (⚠️) mándame el nombre más específico o apellido y reenvía la lista.';
        } else {
          consejo = 'Esos nombres no están en la base. Si son clientes nuevos primero agrégalos con "BEJA carga estos clientes: 573XXX Nombre" y después reenvíame la lista de asistencia. Si te equivocaste de nombre, corrígelo y reenvía.';
        }
        // Si hay encontrados (✓), ofrecer registrarlos ahora sin esperar resolver los otros
        let opcionParcial = '';
        if (encontrados > 0) {
          opcionParcial = '\n\n💡 Si quieres registrar la asistencia de los ' + encontrados + ' encontrado' + (encontrados === 1 ? '' : 's') + ' (✓) ahora mismo y resolver los otros después, dime: "BEJA sí registra los encontrados".';
        }
        admin_text = 'Encontré problemas en la lista:\n' + lineas.join('\n') + '\n\n' + consejo + opcionParcial;
      }
    }
  } else {
    const asisTried = $('Parsear intencion').first().json.asistencias_array || [];
    const results = r.bulk_asis_results || [];
    const deudores = r.bulk_asis_deudores || [];
    const resultsByTel = {};
    for (const x of results) resultsByTel[x.telefono] = x;
    const deudoresByTel = {};
    for (const d of deudores) deudoresByTel[d.telefono] = true;
    const lineas = asisTried.map(a => {
      if (resultsByTel[a.telefono]) {
        return '• ' + a.nombre + ': ahora ' + resultsByTel[a.telefono].clases_restantes + ' clase(s)';
      }
      if (deudoresByTel[a.telefono]) {
        return '• ' + a.nombre + ': 💰 DEUDOR (asistencia registrada sin descuento)';
      }
      return '• ' + a.nombre + ': asistencia registrada';
    });
    const enSaldo0 = results.filter(x => x.clases_restantes === 0);
    const enSaldo1 = results.filter(x => x.clases_restantes === 1);
    const modalidadOut = (r.tipo === 'virtual') ? 'VIRTUALES' : 'presencial' + (asisTried.length === 1 ? '' : 'es');
    admin_text = 'Hecho ✓ Asistencias ' + modalidadOut + ' registradas para ' + asisTried.length + ' persona(s).\n' + lineas.join('\n');
    if (enSaldo0.length + enSaldo1.length > 0) {
      const lowList = [...enSaldo1, ...enSaldo0].map(x => x.nombre || x.telefono);
      admin_text += '\n\n⚠️ Saldo bajo o agotado: ' + lowList.join(', ') + '. Considerar proponer migración a membresía.';
    }
    if (deudores.length > 0) {
      const deudList = deudores.map(d => d.nombre || d.telefono);
      admin_text += '\n\n💰 Deudores (cobrar la asistencia): ' + deudList.join(', ');
    }
    // Construir avisos a clientes (saldo 1 y 0) y alerta de renovacion al grupo (saldo 0).
    // Estos se exponen para que nodos downstream los usen.
    const avisos_clientes = [];
    for (const x of enSaldo1) {
      if (x.telefono) avisos_clientes.push({ telefono: x.telefono, texto: 'Hola ' + (x.nombre || '') + ' te queda 1 clase de tu paquete. Cuando quieras renovamos para que no pierdas el ritmo' });
